import UIKit
import Combine

// MARK: - Models
struct Stock: Codable {
    let symbol: String
    let name: String
    let currentPrice: Double
    let change: Double
    let changePercent: Double
}

struct PortfolioItem: Codable {
    let symbol: String
    let quantity: Int
    let averagePrice: Double
    var currentPrice: Double
    var currentValue: Double { Double(quantity) * currentPrice }
    var profitLoss: Double { currentValue - (Double(quantity) * averagePrice) }
}

struct Trade: Codable {
    let symbol: String
    let type: TradeType
    let quantity: Int
    let price: Double
    let timestamp: Date
    var status: TradeStatus = .pending
    
    enum TradeType: String, Codable {
        case buy
        case sell
    }
    
    enum TradeStatus: String, Codable {
        case pending
        case executed
        case failed
    }
}

// MARK: - Network Layer
class APIService {
    static let shared = APIService()
    private let baseURL = "https://api.example.com"
    
    private init() {}
    
    func fetchStocks() -> AnyPublisher<[Stock], Error> {
        guard let url = URL(string: "\(baseURL)/stocks") else {
            return Fail(error: URLError(.badURL))
                .eraseToAnyPublisher()
        }
        
        return URLSession.shared.dataTaskPublisher(for: url)
            .map(\.data)
            .decode(type: [Stock].self, decoder: JSONDecoder())
            .receive(on: DispatchQueue.main)
            .eraseToAnyPublisher()
    }
    
    func executeTrade(_ trade: Trade) -> AnyPublisher<Trade, Error> {
        guard let url = URL(string: "\(baseURL)/trade") else {
            return Fail(error: URLError(.badURL))
                .eraseToAnyPublisher()
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let encoder = JSONEncoder()
        encoder.keyEncodingStrategy = .convertToSnakeCase
        request.httpBody = try? encoder.encode(trade)
        
        return URLSession.shared.dataTaskPublisher(for: request)
            .map(\.data)
            .decode(type: Trade.self, decoder: JSONDecoder())
            .receive(on: DispatchQueue.main)
            .eraseToAnyPublisher()
    }
}

// MARK: - Trade Manager
class TradeManager: ObservableObject {
    @Published var portfolio: [PortfolioItem] = []
    @Published var trades: [Trade] = []
    
    private var cancellables = Set<AnyCancellable>()
    
    func buyStock(symbol: String, quantity: Int, price: Double) {
        let trade = Trade(symbol: symbol, type: .buy, quantity: quantity, price: price, timestamp: Date())
        executeTrade(trade)
    }
    
    func sellStock(symbol: String, quantity: Int, price: Double) {
        let trade = Trade(symbol: symbol, type: .sell, quantity: quantity, price: price, timestamp: Date())
        executeTrade(trade)
    }
    
    private func executeTrade(_ trade: Trade) {
        APIService.shared.executeTrade(trade)
            .sink(
                receiveCompletion: { _ in },
                receiveValue: { [weak self] executedTrade in
                    self?.trades.append(executedTrade)
                    self?.updatePortfolio(for: executedTrade)
                }
            )
            .store(in: &cancellables)
    }
    
    private func updatePortfolio(for trade: Trade) {
        guard let index = portfolio.firstIndex(where: { $0.symbol == trade.symbol }) else {
            if trade.type == .buy {
                let newItem = PortfolioItem(
                    symbol: trade.symbol,
                    quantity: trade.quantity,
                    averagePrice: trade.price,
                    currentPrice: trade.price
                )
                portfolio.append(newItem)
            }
            return
        }
        
        let item = portfolio[index]
        if trade.type == .buy {
            let totalQuantity = item.quantity + trade.quantity
            let totalCost = (item.quantity * item.averagePrice) + (trade.quantity * trade.price)
            portfolio[index] = PortfolioItem(
                symbol: trade.symbol,
                quantity: totalQuantity,
                averagePrice: totalCost / Double(totalQuantity),
                currentPrice: trade.price
            )
        } else {
            let newQuantity = item.quantity - trade.quantity
            if newQuantity <= 0 {
                portfolio.remove(at: index)
            } else {
                portfolio[index] = PortfolioItem(
                    symbol: trade.symbol,
                    quantity: newQuantity,
                    averagePrice: item.averagePrice,
                    currentPrice: trade.price
                )
            }
        }
    }
}

// MARK: - View Controllers
class StockListViewController: UIViewController {
    @IBOutlet weak var tableView: UITableView!
    
    private var stocks: [Stock] = []
    private let tradeManager = TradeManager()
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
        loadStocks()
    }
    
    private func setupUI() {
        title = "Stocks"
        tableView.delegate = self
        tableView.dataSource = self
        tableView.register(UITableViewCell.self, forCellReuseIdentifier: "StockCell")
    }
    
    private func loadStocks() {
        APIService.shared.fetchStocks()
            .sink(
                receiveCompletion: { _ in },
                receiveValue: { [weak self] stocks in
                    self?.stocks = stocks
                    self?.tableView.reloadData()
                }
            )
            .store(in: &tradeManager.cancellables)
    }
}

extension StockListViewController: UITableViewDataSource, UITableViewDelegate {
    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        stocks.count
    }
    
    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: "StockCell", for: indexPath)
        let stock = stocks[indexPath.row]
        cell.textLabel?.text = "\(stock.symbol) - \(stock.name)"
        cell.detailTextLabel?.text = "\(stock.currentPrice) (\(stock.changePercent)%))"
        return cell
    }
    
    func tableView(_ tableView: UITableView, didSelectRowAt indexPath: IndexPath) {
        let stock = stocks[indexPath.row]
        let tradeVC = TradeViewController()
        tradeVC.stock = stock
        tradeVC.tradeManager = tradeManager
        navigationController?.pushViewController(tradeVC, animated: true)
    }
}

class TradeViewController: UIViewController {
    @IBOutlet weak var symbolLabel: UILabel!
    @IBOutlet weak var priceLabel: UILabel!
    @IBOutlet weak var quantityTextField: UITextField!
    @IBOutlet weak var buyButton: UIButton!
    @IBOutlet weak var sellButton: UIButton!
    
    var stock: Stock!
    var tradeManager: TradeManager!
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
    }
    
    private func setupUI() {
        title = "Trade"
        symbolLabel.text = stock.symbol
        priceLabel.text = "Price: \(stock.currentPrice)"
        quantityTextField.placeholder = "Quantity"
        quantityTextField.keyboardType = .numberPad
        
        buyButton.backgroundColor = .systemGreen
        sellButton.backgroundColor = .systemRed
    }
    
    @IBAction func buyTapped(_ sender: UIButton) {
        guard let quantity = Int(quantityTextField.text ?? "0"), quantity > 0 else {
            showAlert(message: "Please enter a valid quantity")
            return
        }
        tradeManager.buyStock(symbol: stock.symbol, quantity: quantity, price: stock.currentPrice)
        showAlert(message: "Buy order submitted")
    }
    
    @IBAction func sellTapped(_ sender: UIButton) {
        guard let quantity = Int(quantityTextField.text ?? "0"), quantity > 0 else {
            showAlert(message: "Please enter a valid quantity")
            return
        }
        tradeManager.sellStock(symbol: stock.symbol, quantity: quantity, price: stock.currentPrice)
        showAlert(message: "Sell order submitted")
    }
    
    private func showAlert(message: String) {
        let alert = UIAlertController(title: "Trade", message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

